## 2.  `pcapng_stubs.cpp` – C/C++ glue  

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp
   C++ implementation of the OCaml bindings declared in pcapng.mli.
   Compile with:
       ocamlc -c -I +ocaml pcapng_stubs.cpp   # produces pcapng_stubs.o
   and link the resulting object with the OCaml code (or build a .cmxa).

   The file must be compiled as C++ (g++/clang++) because it talks to the
   libpcapng C++ API.  All entry points that OCaml will call are declared
   as `extern "C"` so that the OCaml linker can find them.
   ---------------------------------------------------------------------- */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/bigarray.h>
#include <caml/fail.h>
#include <caml/byterun.h>
#include <caml/signals.h>
#include <caml/intext.h>
#include <caml/threads.h>

#include <exception>
#include <string>
#include <vector>
#include <cstring>   // memcpy
#include <cstdint>   // int64_t

/* ------------------------------------------------------------
   The libpcapng C++ API we are binding to.
   (Replace the includes / namespace with the real ones you have.)
   ------------------------------------------------------------ */
#include "pcapng.hpp"          // <-- the public header of libpcapng

/* ------------------------------------------------------------
   OCaml custom block that holds a pointer to the C++ Reader.
   ------------------------------------------------------------ */
struct caml_pcapng_handle {
    pcapng::Reader *reader;          // owned, freed in the finaliser
};

static void caml_pcapng_finalize(value v)
{
    caml_pcapng_handle *h = *(caml_pcapng_handle **)Data_custom_val(v);
    if (h) {
        delete h->reader;
        caml_stat_free(h);
    }
}

/* We do not need a comparison function, hash, serialize, deserialize.
   The simplest custom operations table is therefore: */
static struct custom_operations caml_pcapng_ops = {
    "pcapng.handle",
    caml_pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------
   Helper: allocate a custom block wrapping a newly created handle.
   ------------------------------------------------------------ */
static value caml_alloc_handle(pcapng::Reader *r)
{
    caml_pcapng_handle *h = (caml_pcapng_handle *)caml_stat_alloc(sizeof(*h));
    h->reader = r;
    value v = caml_alloc_custom(&caml_pcapng_ops,
                                sizeof(caml_pcapng_handle *),
                                0,   // memory used for the block itself
                                1);  // number of custom blocks that may contain it
    Store_custom_val(v, h);
    return v;
}

/* ------------------------------------------------------------
   open_file : string -> t
   ------------------------------------------------------------ */
extern "C" CAMLprim value ocaml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char *c_path = String_val(v_path);

    try {
        // The libpcapng Reader ctor may throw std::runtime_error
        pcapng::Reader *r = new pcapng::Reader(c_path);
        v_res = caml_alloc_handle(r);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown C++ exception while opening file");
    }

    CAMLreturn(v_res);
}

/* ------------------------------------------------------------
   close : t -> unit
   ------------------------------------------------------------ */
extern "C" CAMLprim value ocaml_pcapng_close(value v_handle)
{
    CAMLparam1(v_handle);
    caml_pcapng_handle *h = *(caml_pcapng_handle **)Data_custom_val(v_handle);
    if (h) {
        delete h->reader;
        h->reader = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------
   Helper: build an OCaml frame record from a C++ pcapng::Frame.
   ------------------------------------------------------------ */
static value caml_make_frame(const pcapng::Frame &f)
{
    CAMLparam0();
    CAMLlocal1(v_frame);

    /* The OCaml record has 5 fields, all mutable (the record is immutable,
       but its fields are values, which may be mutable).  We allocate it
       with tag 0 (the default). */
    v_frame = caml_alloc(5, 0);

    /* ts_sec : int64 */
    Store_field(v_frame, 0, caml_copy_int64((int64_t)f.timestamp_sec));

    /* ts_usec : int */
    Store_field(v_frame, 1, Val_int((int)f.timestamp_usec));

    /* captured_len : int */
    Store_field(v_frame, 2, Val_int((int)f.captured_len));

    /* original_len : int */
    Store_field(v_frame, 3, Val_int((int)f.original_len));

    /* data : bytes */
    value v_bytes = caml_alloc_string((mlsize_t)f.captured_len);
    if (f.captured_len > 0)
        memcpy(String_val(v_bytes), f.payload, f.captured_len);
    Store_field(v_frame, 4, v_bytes);

    CAMLreturn(v_frame);
}

/* ------------------------------------------------------------
   iter : t -> (frame -> unit) -> unit
   ------------------------------------------------------------ */
extern "C" CAMLprim value ocaml_pcapng_iter(value v_handle, value v_cb)
{
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_frame);

    caml_pcapng_handle *h = *(caml_pcapng_handle **)Data_custom_val(v_handle);
    if (!h || !h->reader)
        caml_failwith("pcapng: iterator used after close");

    /* The callback must be kept alive while we are iterating.  The
       simplest way is to register it as a global root.  The root is
       removed again before returning. */
    caml_register_global_root(&v_cb);

    try {
        for (const pcapng::Frame &f : *(h->reader)) {
            /* Build the OCaml frame record */
            v_frame = caml_make_frame(f);
            /* Call the user supplied OCaml function */
            caml_callback(v_cb, v_frame);
            /* Allow OCaml async exceptions (Ctrl‑C) to be processed */
            caml_process_pending_signals();
        }
    } catch (const std::exception &e) {
        caml_remove_global_root(&v_cb);
        caml_failwith(e.what());
    } catch (...) {
        caml_remove_global_root(&v_cb);
        caml_failwith("pcapng: unknown C++ exception during iteration");
    }

    caml_remove_global_root(&v_cb);
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------
   next : t -> frame option
   ------------------------------------------------------------ */
extern "C" CAMLprim value ocaml_pcapng_next(value v_handle)
{
    CAMLparam1(v_handle);
    CAMLlocal1(v_res);

    caml_pcapng_handle *h = *(caml_pcapng_handle **)Data_custom_val(v_handle);
    if (!h || !h->reader)
        caml_failwith("pcapng: next used after close");

    try {
        if (h->reader->has_next()) {
            pcapng::Frame f = h->reader->next();
            v_res = caml_alloc(1, 0);            // Some(...)
            Store_field(v_res, 0, caml_make_frame(f));
        } else {
            v_res = Val_int(0);                  // None
        }
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    } catch (...) {
        caml_failwith("pcapng: unknown C++ exception in next");
    }

    CAMLreturn(v_res);
}
```

